/**
 * Tests for the WorktreeCreate enter-registrar hook — M168 Phase 4 (#1914).
 *
 * Verifies the children-bus directory is initialized in the new worktree
 * and the pending-link marker is written under the parent project_dir so
 * the child's session-registrar can later resolve the link.
 */

import { describe, it, expect, beforeEach, afterEach } from 'vitest';
import { existsSync, mkdtempSync, readFileSync, rmSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { join } from 'node:path';

import { enterRegistrar } from '../../worktree/enter-registrar.js';
import { NOOP_CTX } from '../../lib/context.js';
import { childrenDir } from '../../lib/children-bus.js';
import type { HookInput } from '../../types.js';

function makeInput(sid: string, projectDir: string, name: string): HookInput {
  return {
    hook_event: 'WorktreeCreate',
    tool_name: '',
    session_id: sid,
    tool_input: {},
    project_dir: projectDir,
    name,
  } as HookInput;
}

describe('worktree/enter-registrar (#1914)', () => {
  let projectDir: string;

  beforeEach(() => {
    projectDir = mkdtempSync(join(tmpdir(), 'ork-enter-registrar-'));
  });

  afterEach(() => {
    rmSync(projectDir, { recursive: true, force: true });
  });

  it('initializes the children-bus directory in the new worktree', () => {
    const res = enterRegistrar(makeInput('s-parent', projectDir, 'feature-a'), NOOP_CTX);
    expect(res.continue).toBe(true);

    const worktreePath = join(projectDir, '.worktrees', 'feature-a');
    const dir = childrenDir(worktreePath);
    expect(existsSync(dir)).toBe(true);
    expect(existsSync(join(dir, '.gitkeep'))).toBe(true);
  });

  it('writes the pending-link marker under the parent project_dir', () => {
    enterRegistrar(makeInput('s-parent', projectDir, 'feature-b'), NOOP_CTX);

    const markerPath = join(projectDir, '.claude', 'state', 'worktree-pending', 'feature-b.json');
    expect(existsSync(markerPath)).toBe(true);

    const parsed = JSON.parse(readFileSync(markerPath, 'utf8'));
    expect(parsed.parent_sid).toBe('s-parent');
    expect(parsed.name).toBe('feature-b');
    expect(parsed.worktree_path).toBe(join(projectDir, '.worktrees', 'feature-b'));
    expect(typeof parsed.created_at).toBe('number');
  });

  it('is a no-op when session_id is missing', () => {
    const input = {
      hook_event: 'WorktreeCreate',
      tool_name: '',
      session_id: '',
      tool_input: {},
      project_dir: projectDir,
      name: 'never',
    } as HookInput;
    const res = enterRegistrar(input, NOOP_CTX);
    expect(res.continue).toBe(true);
    // Nothing should have been written.
    expect(existsSync(join(projectDir, '.claude', 'state', 'worktree-pending', 'never.json'))).toBe(false);
  });

  it('falls back to "unknown" slug when name is missing', () => {
    const input = {
      hook_event: 'WorktreeCreate',
      tool_name: '',
      session_id: 's-parent',
      tool_input: {},
      project_dir: projectDir,
    } as HookInput;
    enterRegistrar(input, NOOP_CTX);
    expect(existsSync(join(projectDir, '.claude', 'state', 'worktree-pending', 'unknown.json'))).toBe(true);
  });

  it('overwrites an existing pending marker for the same slug', () => {
    enterRegistrar(makeInput('s-parent', projectDir, 'feature-c'), NOOP_CTX);
    enterRegistrar(makeInput('s-other', projectDir, 'feature-c'), NOOP_CTX);

    const markerPath = join(projectDir, '.claude', 'state', 'worktree-pending', 'feature-c.json');
    const parsed = JSON.parse(readFileSync(markerPath, 'utf8'));
    expect(parsed.parent_sid).toBe('s-other');
  });
});
